{"code": "import json
import re

# Read the full books data
books_file_path = var_functions.query_db:12
with open(books_file_path, 'r') as f:
    books_data = json.load(f)

# Extract publication year from details
books_with_years = []
for book in books_data:
    details = book.get('details', '')
    # Look for year patterns in details
    year_matches = re.findall(r'(?:released|released on|published|published on|edition on|edition) (?:[A-Za-z]+ )?\d{1,2},? (\d{4})', details, re.IGNORECASE)
    if not year_matches:
        year_matches = re.findall(r'(\d{4})', details)

    year = None
    if year_matches:
        # Filter for reasonable years (1900-2023)
        for match in year_matches:
            try:
                y = int(match)
                if 1900 <= y <= 2023:
                    year = y
                    break
            except:
                continue

    if year:
        books_with_years.append({
            'book_id': book['book_id'],
            'title': book.get('title', ''),
            'year': year,
            'decade': f"{year//10*10}s"
        })

print("__RESULT__:")
print(json.dumps(books_with_years[:20], indent=2))"}

