                if 1900 <= y <= 2023:
                    year = y
                    break
            except:
                continue

    if year:
        books_with_years.append({
            'book_id': book['book_id'],
            'title': book_title,
            'year': year,
            'decade': f"{year//10*10}s"
        })

print("__RESULT__:")
print(json.dumps({
    'total_books': len(books_data),
