import re
from collections import defaultdict

# Read books data
var_name = 'var_functions.query_db:28'
books_file_path = locals()[var_name]
with open(books_file_path, 'r') as f:
    books_data = json.load(f)

# Read review data
var_name2 = 'var_functions.query_db:30'
review_file_path = locals()[var_name2]
with open(review_file_path, 'r') as f:
    review_data = json.load(f)

# Extract book_id and publication year from books
book_years = {}
for book in books_data:
    details = book.get('details', '')
    book_id = book['book_id']
    title = book.get('title', '')

    # Extract year from details
    year_matches = re.findall(r'(?:released|released on|published|published on|edition on|edition) (?:[A-Za-z]+ )?\d{1,2},? (\d{4})', details, re.IGNORECASE)
    if not year_matches:
        year_matches = re.findall(r'(\d{4})', details)

    year = None
    if year_matches:
        for match in year_matches:
            try:
                y = int(match)
                if 1900 <= y <= 2023:
                    year = y
                    break
            except:
                continue

    if year:
        decade = f"{year//10*10}s"
        book_years[book_id] = {
            'title': title,
            'year': year,
            'decade': decade
        }

# Extract purchase_id and rating from reviews
purchase_ratings = {}
for review in review_data:
    purchase_id = review.get('purchase_id')
    rating = review.get('rating')
    if purchase_id and rating:
        purchase_ratings[purchase_id] = float(rating)

# Match books with reviews by extracting numeric ID
book_id_to_purchase_id = {}
for book_id in book_years.keys():
    # Extract numeric part from book_id (e.g., "bookid_1" -> "1")
    match = re.search(r'bookid_(\d+)', book_id)
    if match:
        numeric_id = match.group(1)
        purchase_id = f"purchaseid_{numeric_id}"
        if purchase_id in purchase_ratings:
            book_id_to_purchase_id[book_id] = purchase_id

print(f"Books with years: {len(book_years)}")
print(f"Purchase ratings: {len(purchase_ratings)}")
print(f"Matched books: {len(book_id_to_purchase_id)}")"}

